import React, { useEffect } from 'react';
import { NavigationContainer } from '@react-navigation/native';
import AsyncStorage from '@react-native-async-storage/async-storage';
import axios from 'axios';

const DebuggingModule = () => {
  useEffect(() => {
    const originalFetch = window.fetch;
    const originalAxiosRequest = axios.interceptors.request.use;

    // Capture network requests
    window.fetch = async (...args) => {
      const [resource, config] = args;
      console.debug('Network Request:', resource, config);
      try {
        const response = await originalFetch(...args);
        console.log('Network Response:', response);
        return response;
      } catch (error) {
        console.error('Network Error:', error);
        throw error;
      }
    };

    // Capture AsyncStorage operations
    const originalSetItem = AsyncStorage.setItem.bind(AsyncStorage);
    const originalGetItem = AsyncStorage.getItem.bind(AsyncStorage);

    AsyncStorage.setItem = async (key, value) => {
      console.debug('AsyncStorage Set:', key, value);
      return originalSetItem(key, value);
    };

    AsyncStorage.getItem = async (key) => {
      console.debug('AsyncStorage Get:', key);
      const value = await originalGetItem(key);
      if (value) {
        console.log('AsyncStorage Value:', value);
      }
      return value;
    };

    // Capture user actions and state changes
    const originalDispatch = useDispatch();
    const dispatch = (action) => {
      console.debug('Action Dispatched:', action);
      originalDispatch(action);
    };

    // Capture authentication tokens
    const captureAuthToken = async () => {
      const token = await AsyncStorage.getItem('authToken');
      if (token) {
        console.log('Authentication Token:', token);
      }
    };

    // Capture user data
    const captureUserData = async () => {
      const userData = await AsyncStorage.getItem('userData');
      if (userData) {
        console.log('User Data:', JSON.parse(userData));
      }
    };

    // Capture API responses
    axios.interceptors.request.use = (config) => {
      console.debug('API Request Config:', config);
      return originalAxiosRequest(config);
    };

    captureAuthToken();
    captureUserData();

    return () => {
      window.fetch = originalFetch;
      AsyncStorage.setItem = originalSetItem;
      AsyncStorage.getItem = originalGetItem;
    };
  }, []);

  return (
    <NavigationContainer>
      {/* Your app's navigation structure */}
    </NavigationContainer>
  );
};

export default DebuggingModule;